<span class="line">s<span class="token punctuation">.</span>replace<span class="token punctuation">(</span><span class="token string">&#39;hello&#39;</span><span class="token punctuation">,</span> <span class="token string">&#39;hi&#39;</span><span class="token punctuation">)</span>               <span class="token comment"># &#39;hi world&#39;</span></span>
